/// Cryptographically secure UUID generator for offline data entries.
/// Uses Random.secure() which leverages the platform's cryptographic RNG.
class SecureUuidGenerator {
  // Use cryptographically secure random number generator
  // Random.secure() uses the platform's CSPRNG (e.g., /dev/urandom on Linux,
  // CryptGenRandom on Windows, SecRandomCopyBytes on iOS/macOS)
  static final Random _secureRandom = Random.secure();

  /// Generates a UUID v4 (random) using cryptographically secure randomness.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is a random hex digit and y is one of 8, 9, a, or b.
  static String generateV4() {
    final bytes = _generateSecureRandomBytes(16);

    // Set version to 4 (0100 in binary) - bits 48-51
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) - bits 64-65
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a time-based UUID with cryptographically secure random component.
  /// Useful for offline entries where ordering by creation time matters.
  /// Format: tttttttt-tttt-4rxx-yxxx-xxxxxxxxxxxx
  /// where t = timestamp hex, r = random, y = variant bits
  static String generateTimeBasedV4() {
    final bytes = _generateSecureRandomBytes(16);
    final timestamp = DateTime.now().millisecondsSinceEpoch;

    // Encode timestamp into the first 6 bytes (48 bits)
    // This gives us ordering capability while maintaining uniqueness
    bytes[0] = (timestamp >> 40) & 0xFF;
    bytes[1] = (timestamp >> 32) & 0xFF;
    bytes[2] = (timestamp >> 24) & 0xFF;
    bytes[3] = (timestamp >> 16) & 0xFF;
    bytes[4] = (timestamp >> 8) & 0xFF;
    bytes[5] = timestamp & 0xFF;

    // Set version to 4
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    return _formatUuid(bytes);
  }

  /// Generates a compact UUID without hyphens for storage efficiency.
  static String generateCompact() {
    return generateV4().replaceAll('-', '');
  }

  /// Generates a short unique ID (12 hex characters) for cases where
  /// full UUID length is not needed. Still cryptographically secure.
  static String generateShortId() {
    final bytes = _generateSecureRandomBytes(6);
    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  /// Generates a batch of UUIDs for bulk offline record creation.
  static List<String> generateBatch(int count) {
    if (count <= 0 || count > 10000) {
      throw ArgumentError('Count must be between 1 and 10000');
    }
    return List.generate(count, (_) => generateV4());
  }

  /// Validates whether a string is a valid UUID v4 format.
  static bool isValidUuid(String uuid) {
    final regex = RegExp(
      r'^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$',
      caseSensitive: false,
    );
    return regex.hasMatch(uuid);
  }

  /// Generates cryptographically secure random bytes.
  static List<int> _generateSecureRandomBytes(int length) {
    return List<int>.generate(length, (_) => _secureRandom.nextInt(256));
  }

  /// Formats 16 bytes into standard UUID string representation.
  static String _formatUuid(List<int> bytes) {
    assert(bytes.length == 16);
    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${hex.substring(0, 8)}-'
        '${hex.substring(8, 12)}-'
        '${hex.substring(12, 16)}-'
        '${hex.substring(16, 20)}-'
        '${hex.substring(20, 32)}';
  }
}

/// Model representing an offline data entry with a secure UUID.
class OfflineDataEntry {
  final String id;
  final String data;
  final DateTime createdAt;
  final bool isSynced;
  final String? syncedAt;

  OfflineDataEntry({
    String? id,
    required this.data,
    DateTime? createdAt,
    this.isSynced = false,
    this.syncedAt,
  })  : id = id ?? SecureUuidGenerator.generateV4(),
        createdAt = createdAt ?? DateTime.now();

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'data': data,
      'createdAt': createdAt.toIso8601String(),
      'isSynced': isSynced,
      'syncedAt': syncedAt,
    };
  }

  factory OfflineDataEntry.fromJson(Map<String, dynamic> json) {
    return OfflineDataEntry(
      id: json['id'] as String,
      data: json['data'] as String,
      createdAt: DateTime.parse(json['createdAt'] as String),
      isSynced: json['isSynced'] as bool? ?? false,
      syncedAt: json['syncedAt'] as String?,
    );
  }

  OfflineDataEntry copyWith({
    String? id,
    String? data,
    DateTime? createdAt,
    bool? isSynced,
    String? syncedAt,
  }) {
    return OfflineDataEntry(
      id: id ?? this.id,
      data: data ?? this.data,
      createdAt: createdAt ?? this.createdAt,
      isSynced: isSynced ?? this.isSynced,
      syncedAt: syncedAt ?? this.syncedAt,
    );
  }

  @override
  String toString() =>
      'OfflineDataEntry(id: $id, data: $data, synced: $isSynced)';
}

/// Simple in-memory store for offline entries (replace with persistent storage in production).
class OfflineEntryStore {
  final Map<String, OfflineDataEntry> _entries = {};

  void add(OfflineDataEntry entry) {
    if (_entries.containsKey(entry.id)) {
      throw StateError('Entry with ID ${entry.id} already exists');
    }
    _entries[entry.id] = entry;
  }

  OfflineDataEntry? get(String id) => _entries[id];

  List<OfflineDataEntry> getAll() => _entries.values.toList();

  List<OfflineDataEntry> getUnsynced() =>
      _entries.values.where((e) => !e.isSynced).toList();

  void markSynced(String id) {
    final entry = _entries[id];
    if (entry != null) {
      _entries[id] = entry.copyWith(
        isSynced: true,
        syncedAt: DateTime.now().toIso8601String(),
      );
    }
  }

  void remove(String id) => _entries.remove(id);

  int get count => _entries.length;

  int get unsyncedCount => _entries.values.where((e) => !e.isSynced).length;

  void clear() => _entries.clear();
}

