        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Text(
              '🧪 Uniqueness Test',
              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 8),
            const Text(
              'Generate 10,000 UUIDs and verify zero collisions:',
              style: TextStyle(fontSize: 14),
            ),
            const SizedBox(height: 12),
            FilledButton.tonalIcon(
              onPressed: _runCollisionTest,
              icon: const Icon(Icons.science),
              label: const Text('Run Collision Test'),
            ),
          ],
        ),
      ),
    );
  }

  void _runCollisionTest() {
    final stopwatch = Stopwatch()..start();
    const count = 10000;
    final uuids = <String>{};
    int collisions = 0;

    for (int i = 0; i < count; i++) {
      final uuid = SecureUuidGenerator.generateV4();
      if (!uuids.add(uuid)) {
        collisions++;
      }
    }

    stopwatch.stop();

    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('🧪 Test Results'),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text('Generated: $count UUIDs'),
            Text('Unique: ${uuids.length}'),
            Text(
              'Collisions: $collisions',
              style: TextStyle(
                color: collisions == 0 ? Colors.green : Colors.red,
                fontWeight: FontWeight.bold,
              ),
            ),
            Text('Time: ${stopwatch.elapsedMilliseconds}ms'),
            Text(
              'Rate: ${(count / (stopwatch.elapsedMilliseconds / 1000)).toStringAsFixed(0)} UUIDs/sec',
            ),
            const SizedBox(height: 12),
            Text(
              collisions == 0
                  ? '✅ All UUIDs are unique!'
                  : '❌ Collisions detected (this should never happen)',
              style: TextStyle(
                fontWeight: FontWeight.bold,
                color: collisions == 0 ? Colors.green : Colors.red,
              ),
            ),
          ],
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }

  String _formatDateTime(DateTime dt) {
    return '${dt.year}-${dt.month.toString().padLeft(2, '0')}-'
        '${dt.day.toString().padLeft(2, '0')} '
        '${dt.hour.toString().padLeft(2, '0')}:'
        '${dt.minute.toString().padLeft(2, '0')}:'
        '${dt.second.toString().padLeft(2, '0')}';
  }
}